            </button>
            {isCriteriaVisible && (
                <div className="mt-4 animate-fade-in-fast">
                    <ScoringCriteriaTable />
                </div>
            )}
        </div>

        {rankedComplexes.length > 0 ? (
          <section>
            <h3 className="text-xl font-semibold text-brand-darkgray dark:text-gray-100 mb-4">{pdfReportTemplate.portfolio_section_title}</h3>
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-2 text-right">* 항목을 클릭하면 지도와 상세 정보를 확인할 수 있습니다.</p>
             <div className="overflow-x-auto rounded-lg border dark:border-gray-700">
                <table className="w-full text-left">
                    <thead className="bg-brand-gray dark:bg-gray-700">
                        <tr className="border-b dark:border-gray-600">
                            <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200">순위</th>
                            <th className="p-3 font-semibold text-sm text-gray-700 dark:text-gray-200">산업단지</th>
                            <th className="p-3 font-semibold text-sm text-gray-700 dark:text-gray-200">근거 측정소<span className="block font-normal text-xs">(거리)</span></th>
