import React from 'react';
import appConfig from '../config/app_config';
import { ScoringCriteria } from '../types';

interface ScoringCriteriaTableProps {
    title?: string;
}

export const ScoringCriteriaTable: React.FC<ScoringCriteriaTableProps> = ({ title }) => {
    const crit: ScoringCriteria = appConfig.scoringCriteria;

    const criteriaData = [
        { category: '시급성 (U)', component: 'U1 (최신농도)', description: `최신 1시간 평균 농도 1µg/m³당 0.5점 부여. (${crit.U1.threshold_high}µg/m³ 이상에서 최고점)`, maxScore: crit.U1.max_score },
        { category: '시급성 (U)', component: 'U2 (급상승)', description: `최근 2시간 농도 변화량 기반. 농도 상승폭이 ${crit.U2.threshold_high}µg/m³일 때 최고점.`, maxScore: crit.U2.max_score },
        { category: '심각성 (S)', component: 'S1 (최대농도)', description: `분석 기간 내 5분 단위 최대 농도 1µg/m³당 0.2점 부여. (${crit.S1.threshold_high}µg/m³ 이상에서 최고점)`, maxScore: crit.S1.max_score },
        { category: '심각성 (S)', component: 'S2 (최근성)', description: '최대 농도 발생 시점이 최근일수록 높은 점수.', maxScore: crit.S2.max_score },
        { category: '지속성 (P)', component: 'P1 (평균농도)', description: `평균 농도 ${crit.P1.threshold_low}µg/m³ 이상일 때 초과분 1µg/m³당 0.5점 부여. (${crit.P1.threshold_high}µg/m³ 이상에서 최고점)`, maxScore: crit.P1.max_score },
        { category: '신뢰성 (D)', component: 'D1 (데이터품질)', description: `이상 최고농도(${crit.D1.anomaly_threshold}µg/m³) 감지 시 ${crit.D1.penalty_anomaly}점, 장기 동일값(${crit.D1.constant_run_threshold / 12}시간) 감지 시 ${crit.D1.penalty_constant}점 감점.`, maxScore: 0 },
        { category: '신뢰성 (D)', component: 'D2 (근접성 점수)', description: `산업단지와 측정소 거리가 가까울수록 높은 점수 부여. ${crit.D2.max_distance_km}km 이상 시 0점, 0km 근접 시 최고점.`, maxScore: crit.D2.max_score },
    ];

    const mergedRows = [];
    let lastCategory = '';

    criteriaData.forEach((item, index) => {
        if (item.category !== lastCategory) {
            const rowSpan = criteriaData.filter(d => d.category === item.category).length;
            mergedRows.push({ ...item, rowSpan, isFirst: true });
            lastCategory = item.category;
        } else {
            mergedRows.push({ ...item, rowSpan: 1, isFirst: false });
        }
    });

    return (
        <section>
            {title && <h3 className="text-xl font-semibold text-brand-darkgray dark:text-gray-200 mb-4">{title}</h3>}
            <div className="overflow-x-auto rounded-lg border dark:border-gray-700">
                <table className="w-full text-left text-sm">
                    <thead className="bg-brand-gray dark:bg-gray-700 text-gray-700 dark:text-gray-200">
                        <tr>
                            <th className="p-3 font-semibold w-1/6">구분</th>
                            <th className="p-3 font-semibold w-1/6">항목</th>
                            <th className="p-3 font-semibold w-2/3">산정 기준</th>
                            <th className="p-3 text-center font-semibold">최고점</th>
                        </tr>
                    </thead>
                    <tbody>
                        {mergedRows.map((item, index) => (
                            <tr key={index} className="border-b dark:border-gray-600 last:border-b-0 hover:bg-gray-50 dark:hover:bg-gray-700">
                                {item.isFirst && <td className="p-3 align-top text-gray-800 dark:text-gray-300" rowSpan={item.rowSpan}>{item.category}</td>}
                                <td className="p-3 font-medium text-gray-800 dark:text-gray-300">{item.component}</td>
                                <td className="p-3 text-gray-600 dark:text-gray-400">{item.description}</td>
                                <td className="p-3 text-center font-medium text-gray-800 dark:text-gray-300">{item.maxScore > 0 ? item.maxScore : '감점'}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </section>
    );
};

import React, { useEffect, useRef } from 'react';
import { IndustrialComplex } from '../types';

interface StationMapProps {
    complex: IndustrialComplex;
    stationName: string;
    stationLat?: number;
    stationLon?: number;
    stationAddress?: string;
}

declare const L: any; // Leaflet global type

export const StationMap: React.FC<StationMapProps> = ({ complex, stationName, stationLat, stationLon, stationAddress }) => {
    const mapRef = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<any>(null);

    useEffect(() => {
        if (!mapRef.current) return;
        if (!stationLat || !stationLon) return;

        if (mapInstance.current) {
            mapInstance.current.remove();
        }

        try {
            const map = L.map(mapRef.current).setView([complex.lat, complex.lon], 11);
            mapInstance.current = map;

            L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                attribution: '&copy; OpenStreetMap contributors'
            }).addTo(map);

            // Icon definitions
            const complexIcon = L.icon({
                iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png',
                shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png',
                iconSize: [25, 41],
                iconAnchor: [12, 41],
                popupAnchor: [1, -34],
                shadowSize: [41, 41]
            });

            const stationIcon = L.icon({
                iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-blue.png',
                shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png',
                iconSize: [25, 41],
                iconAnchor: [12, 41],
                popupAnchor: [1, -34],
                shadowSize: [41, 41]
            });

            // Add markers
            const cMarker = L.marker([complex.lat, complex.lon], { icon: complexIcon }).addTo(map);
            cMarker.bindPopup(`<b>산업단지: ${complex.name}</b><br/>${complex.address}`).openPopup();

            const sMarker = L.marker([stationLat, stationLon], { icon: stationIcon }).addTo(map);
            sMarker.bindPopup(`<b>측정소: ${stationName}</b><br/>${stationAddress || '주소 정보 없음'}`);

            // Draw line
            const latlngs = [
                [complex.lat, complex.lon],
                [stationLat, stationLon]
            ];
            const polyline = L.polyline(latlngs, {color: 'blue', weight: 3, opacity: 0.5, dashArray: '10, 10'}).addTo(map);

            // Fit bounds
            const group = new L.featureGroup([cMarker, sMarker]);
            map.fitBounds(group.getBounds().pad(0.2));

        } catch (e) {
            console.error("Map initialization failed", e);
        }

        return () => {
            if (mapInstance.current) {
                mapInstance.current.remove();
                mapInstance.current = null;
            }
        };
    }, [complex, stationName, stationLat, stationLon, stationAddress]);

    return (
        <div className="flex flex-col space-y-2">
            {!stationLat || !stationLon ? (
                <div className="h-64 w-full bg-gray-100 dark:bg-gray-700 flex items-center justify-center text-gray-500 dark:text-gray-300 rounded-lg">
                    지도 위치 정보를 불러올 수 없습니다.
                </div>
            ) : (
                <div ref={mapRef} className="h-64 w-full rounded-lg border border-gray-300 dark:border-gray-600 shadow-inner z-0" />
            )}

            <div className="bg-gray-50 dark:bg-gray-700 rounded-lg border border-gray-200 dark:border-gray-600 p-3 text-sm">
                <div className="font-semibold text-gray-700 dark:text-gray-200 mb-2 border-b dark:border-gray-600 pb-1">주소 정보 (Address)</div>
                <div className="flex flex-col space-y-2">
                    <div className="flex items-start">
                        <span className="flex-shrink-0 w-3 h-3 rounded-full bg-red-500 mt-1.5 mr-2"></span>
                        <div>
                            <span className="font-bold text-gray-800 dark:text-gray-200">{complex.name}</span>
                            <div className="text-gray-600 dark:text-gray-400 text-xs">{complex.address}</div>
                        </div>
                    </div>
                    <div className="flex items-start">
                        <span className="flex-shrink-0 w-3 h-3 rounded-full bg-blue-500 mt-1.5 mr-2"></span>
                        <div>
                            <span className="font-bold text-gray-800 dark:text-gray-200">{stationName} 측정소</span>
                            <div className="text-gray-600 dark:text-gray-400 text-xs">{stationAddress || '주소 정보 미등록'}</div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

