import { AnalysisResult, AppConfig, PollutantType } from './types';
import { analyzeData } from './services/analysisService';
import appConfig from './config/app_config';
import { LoadingSpinner } from './components/LoadingSpinner';
import { ErrorAlert } from './components/ErrorAlert';
import { IndustrialComplexSelector } from './components/IndustrialComplexSelector';
import { ScoringCriteriaTable } from './components/ScoringCriteriaTable';

const App: React.FC = () => {
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [selectedComplexes, setSelectedComplexes] = useState<string[]>([]);
  const [pollutantType, setPollutantType] = useState<PollutantType>('PM2.5');
  const [resetKey, setResetKey] = useState(0);
  const [showCriteriaModal, setShowCriteriaModal] = useState(false);

  const config: AppConfig = appConfig;

  const readFileAsText = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        resolve(event.target?.result as string);
      };
      reader.onerror = (error) => {
        reject(error);
      };
      reader.readAsText(file, 'EUC-KR');
    });
  };

  const handleFileSelection = useCallback((files: File[]) => {
    setSelectedFiles(files);
    setAnalysisResult(null); 
    setError(null);
  }, []);

  const handleComplexSelection = useCallback((complexNames: string[]) => {
    setSelectedComplexes(complexNames);
  }, []);

  const handleAnalysis = useCallback(async () => {
    if (selectedFiles.length === 0 || selectedComplexes.length === 0) {
      setError("분석을 위해서는 최소 1개의 데이터 파일과 1개의 산업단지를 선택해야 합니다.");
      return;
    }
    setIsLoading(true);
    setError(null);
    setAnalysisResult(null);

    try {
      const readPromises = selectedFiles.map(file => readFileAsText(file));
      const contents = await Promise.all(readPromises);
      const result = analyzeData(contents, selectedComplexes, pollutantType);
      setAnalysisResult(result);
    } catch (e) {
      if (e instanceof Error) {
        setError(e.message);
      } else {
        setError('알 수 없는 오류가 발생했습니다.');
      }
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  }, [selectedFiles, selectedComplexes, pollutantType]);

  const handleReset = useCallback(() => {
    setAnalysisResult(null);
    setError(null);
    setSelectedFiles([]);
    setSelectedComplexes([]);
    setResetKey(prevKey => prevKey + 1);
  }, []);

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 font-sans text-brand-darkgray dark:text-gray-100 transition-colors duration-200">
      <header className="bg-brand-blue shadow-md dark:bg-blue-900">
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex flex-col md:flex-row justify-between items-center gap-4">
            <div>
              <h1 className="text-xl sm:text-2xl lg:text-3xl font-bold text-white tracking-tight">{config.appName}</h1>
              <p className="text-sm text-blue-200 mt-1">v{config.version}</p>
            </div>

            {/* Pollutant Type Switch */}
            <div className="bg-blue-800 dark:bg-blue-950 p-1 rounded-lg flex space-x-1">
               <button
                 onClick={() => { setPollutantType('PM2.5'); setAnalysisResult(null); }}
                 className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${pollutantType === 'PM2.5' ? 'bg-white text-brand-blue shadow' : 'text-blue-200 hover:bg-blue-700'}`}
               >
                 PM2.5 분석
               </button>
               <button
                 onClick={() => { setPollutantType('O3'); setAnalysisResult(null); }}
                 className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${pollutantType === 'O3' ? 'bg-white text-brand-blue shadow' : 'text-blue-200 hover:bg-blue-700'}`}
               >
                 오존(O3) 분석
               </button>
            </div>
          </div>
        </div>
      </header>

      <main className="container mx-auto p-4 sm:p-6 lg:p-8 space-y-8">
        <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 transition-colors">
          <h2 className="text-xl font-semibold text-brand-darkgray dark:text-white border-b dark:border-gray-700 pb-3 mb-4">
              1. 데이터 파일 업로드 ({pollutantType})
          </h2>
          <p className="text-gray-600 dark:text-gray-300 mb-6">
              분석할 {pollutantType === 'PM2.5' ? '초미세먼지(PM2.5)' : '오존(O3)'} 데이터가 포함된 CSV 파일을 업로드해주세요.
          </p>
          <FileUpload key={`file-upload-${resetKey}`} onFileSelect={handleFileSelection} isLoading={isLoading} />
        </div>

        <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 transition-colors">
          <h2 className="text-xl font-semibold text-brand-darkgray dark:text-white border-b dark:border-gray-700 pb-3 mb-4">2. 분석 대상 산업단지 선택</h2>
          <p className="text-gray-600 dark:text-gray-300 mb-6">우선순위를 분석할 산업단지를 선택해주세요.</p>
          <IndustrialComplexSelector 
            key={`complex-selector-${resetKey}`}
            complexes={config.industrialComplexes}
            onSelectionChange={handleComplexSelection}
          />
        </div>

        <div className="flex flex-col sm:flex-row justify-center items-center gap-4">
            <button
              onClick={() => setShowCriteriaModal(true)}
              className="w-full sm:w-auto px-12 py-4 text-lg font-bold text-brand-blue dark:text-blue-300 bg-white dark:bg-gray-800 border-2 border-brand-blue dark:border-blue-500 rounded-lg shadow-md hover:bg-blue-50 dark:hover:bg-gray-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-lightblue transition-colors duration-200"
            >
              평가 기준표 ({pollutantType})
            </button>

            {analysisResult ? (
              <button
                onClick={handleReset}
                className="w-full sm:w-auto px-12 py-4 text-lg font-bold text-white bg-green-600 dark:bg-green-700 rounded-lg shadow-md hover:bg-green-700 dark:hover:bg-green-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition-colors duration-200"
              >
                초기화 및 새로운 분석 시작
              </button>
            ) : (
              <button
                onClick={handleAnalysis}
                disabled={selectedFiles.length === 0 || selectedComplexes.length === 0 || isLoading}
                className="w-full sm:w-auto px-12 py-4 text-lg font-bold text-white bg-brand-blue dark:bg-blue-700 rounded-lg shadow-md hover:bg-brand-lightblue dark:hover:bg-blue-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-blue transition-colors duration-200 disabled:bg-gray-400 disabled:dark:bg-gray-600 disabled:cursor-not-allowed"
              >
                {isLoading ? '분석 중...' : `${pollutantType} 우선순위 분석 실행`}
              </button>
            )}
        </div>

        {isLoading && <LoadingSpinner />}
        {error && <ErrorAlert message={error} />}

        {analysisResult && (
          <div className="mt-8">
            <ReportDisplay result={analysisResult} />
          </div>
        )}
      </main>

      <footer className="text-center py-6 text-sm text-gray-500 dark:text-gray-400">
        <p>&copy; {new Date().getFullYear()} {config.appName}. All rights reserved.</p>
      </footer>

      {showCriteriaModal && (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-center p-4 animate-fade-in-fast">
            <div className="bg-white dark:bg-gray-800 rounded-lg shadow-2xl w-full max-w-4xl p-6 relative max-h-[90vh] overflow-y-auto transition-colors">
                <button 
                    onClick={() => setShowCriteriaModal(false)}
                    className="absolute top-4 right-4 text-gray-500 dark:text-gray-400 hover:text-gray-800 dark:hover:text-gray-100 text-3xl font-light leading-none"
                >
                    &times;
                </button>
                <div className="mt-2 text-brand-darkgray dark:text-gray-100">
                    <ScoringCriteriaTable 
                        title={`${pollutantType} 우선관리 대상 선정 평가 기준`} 
                        mode={pollutantType}
                    />
                </div>
                <div className="mt-6 flex justify-end">
                    <button 
                        onClick={() => setShowCriteriaModal(false)}
                        className="px-6 py-2 bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-gray-200 rounded-md hover:bg-gray-300 dark:hover:bg-gray-600 font-medium transition-colors"
                    >
                        닫기
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { AnalysisResult, AnalyzedComplex, PollutantType } from '../types';
import appConfig from '../config/app_config';
import { InfoIcon, MapIcon } from './icons';
import { ReportViewer } from './ReportViewer';
import { ScoringCriteriaTable } from './ScoringCriteriaTable';
import { StationMap } from './StationMap';

interface ReportDisplayProps {
  result: AnalysisResult;
}

const ChevronDownIcon = (props: React.SVGProps<SVGSVGElement>) => (
    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" {...props}>
      <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 8.25l-7.5 7.5-7.5-7.5" />
    </svg>
);

const ComplexRow: React.FC<{ analyzedComplex: AnalyzedComplex; rank: number; type: PollutantType }> = ({ analyzedComplex, rank, type }) => {
    const [isOpen, setIsOpen] = useState(false);
    const { complex, station, distanceKm, stationLat, stationLon, stationAddress } = analyzedComplex;
    const scores = station.scores!;

    // PM2.5 Helper
    const scoreSum = (val1: number, val2: number) => (val1 + val2).toFixed(1);
    const dTotalPM = (scores.d1 || 0) + (scores.d2 || 0);

    return (
        <>
            <tr 
                className={`border-b dark:border-gray-700 cursor-pointer transition-colors ${isOpen ? 'bg-blue-50 dark:bg-blue-900/20' : 'hover:bg-gray-50 dark:hover:bg-gray-700'}`} 
                onClick={() => setIsOpen(!isOpen)}
                title="클릭하여 지도 및 상세 정보 확인"
            >
                <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{rank}</td>
                <td className="p-3 font-semibold text-sm md:text-base text-gray-800 dark:text-gray-200">{complex.name}</td>
                <td className="p-3 text-sm md:text-base text-gray-800 dark:text-gray-200">{station.name}<span className="block text-xs text-gray-500 dark:text-gray-400">({distanceKm.toFixed(1)}km)</span></td>
                <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{station.metrics.latest_1hr_avg?.toFixed(3) ?? '-'}</td>
                <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{station.metrics.full_period_max?.toFixed(3) ?? '-'}</td>
                <td className="p-3 text-center font-bold text-lg text-brand-blue dark:text-blue-400">{scores.total.toFixed(1)}</td>

                {type === 'PM2.5' ? (
                    <>
                        <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{scoreSum(scores.u1 || 0, scores.u2 || 0)}</td>
                        <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{scoreSum(scores.s1 || 0, scores.s2 || 0)}</td>
                        <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{(scores.p1 || 0).toFixed(1)}</td>
                        <td className={`p-3 text-center font-semibold text-sm md:text-base ${dTotalPM < 0 ? 'text-danger dark:text-red-400' : 'text-green-600 dark:text-green-400'}`}>
                            {dTotalPM.toFixed(1)}
                        </td>
                    </>
                ) : (
                    <>
                        <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{(scores.u || 0).toFixed(1)}</td>
                        <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{(scores.s || 0).toFixed(1)}</td>
                        <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{(scores.p || 0).toFixed(1)}</td>
                        <td className="p-3 text-center text-sm md:text-base text-gray-800 dark:text-gray-200">{(scores.d || 0).toFixed(1)}</td>
                    </>
                )}

                <td className="p-3 text-center">
                    <div className="flex flex-col items-center justify-center space-y-1">
                        <MapIcon className={`h-5 w-5 text-brand-blue dark:text-blue-400 ${isOpen ? 'opacity-100' : 'opacity-60'}`} />
                        <ChevronDownIcon className={`h-4 w-4 text-gray-400 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
                    </div>
                </td>
            </tr>
            {isOpen && (
                <tr className="bg-blue-50 dark:bg-blue-900/10 border-b dark:border-gray-700">
                    <td colSpan={11} className="p-4">
                        <div className="flex flex-col lg:flex-row gap-6 animate-fade-in-fast">
                            <div className="flex-1">
                                <h5 className="font-bold mb-3 text-brand-darkgray dark:text-gray-200">세부 점수 및 근거 데이터 (근거 측정소: {station.name})</h5>
                                <div className="grid grid-cols-2 gap-x-4 gap-y-2 text-sm text-gray-700 dark:text-gray-300">
                                    {type === 'PM2.5' ? (
                                        <>
                                            <div><strong>U1 (최신농도):</strong> {scores.u1} <span className="text-gray-500 dark:text-gray-400">({scores.components['최신 1시간 농도']})</span></div>
                                            <div><strong>U2 (급상승):</strong> {scores.u2} <span className="text-gray-500 dark:text-gray-400">({scores.components['2시간 농도 변화']})</span></div>
                                            <div><strong>S1 (최대농도):</strong> {scores.s1} <span className="text-gray-500 dark:text-gray-400">({scores.components['기간 최대 농도']})</span></div>
                                            <div><strong>S2 (최근성):</strong> {scores.s2} <span className="text-gray-500 dark:text-gray-400">({scores.components['최대농도 최근성']})</span></div>
                                            <div><strong>P1 (평균농도):</strong> {scores.p1} <span className="text-gray-500 dark:text-gray-400">({scores.components['기간 평균 농도']})</span></div>
                                            <div><strong>D1 (데이터품질):</strong> {scores.d1}</div>
                                            {(scores.d2 || 0) > 0 && <div><strong>D2 (근접성 점수):</strong> {scores.d2} <span className="text-gray-500 dark:text-gray-400">({scores.components['근접성 점수']})</span></div>}
                                            <div className="col-span-2"><strong>D1 근거:</strong> 이상값: {scores.components['이상값']}, 장기 동일값: {scores.components['장기 동일값']}</div>
                                        </>
                                    ) : (
                                        <>
                                            <div className="col-span-2"><strong>U (시급성):</strong> {scores.components['U_val']}</div>
                                            <div className="col-span-2"><strong>S (심각성):</strong> {scores.components['S_val']}</div>
                                            <div className="col-span-2"><strong>P (지속성):</strong> {scores.components['P_val']}</div>
                                            <div className="col-span-2"><strong>D (신뢰성):</strong> {scores.components['D_val']}</div>
                                        </>
                                    )}
                                </div>
                            </div>
                            <div className="flex-1 lg:max-w-md">
                                <h5 className="font-bold mb-3 text-brand-darkgray dark:text-gray-200">위치 확인</h5>
                                <div className="rounded-lg overflow-hidden border border-gray-300 dark:border-gray-600 shadow-sm">
                                    <StationMap 
                                        complex={complex} 
                                        stationName={station.name} 
                                        stationLat={stationLat} 
                                        stationLon={stationLon} 
                                        stationAddress={stationAddress}
                                    />
                                </div>
                            </div>
                        </div>
                    </td>
                </tr>
            )}
        </>
    );
};

