                     <p><strong>데이터 분석 기간:</strong> {startTimestamp} ~ {endTimestamp}</p>
                     <p className="mt-2">{summaryIntro}</p>
                  </div>
              </div>
              <button
                  onClick={() => setIsReportVisible(true)}
                  className="flex-shrink-0 flex items-center px-4 py-2 text-sm font-medium text-white bg-brand-blue dark:bg-blue-700 rounded-lg shadow-sm hover:bg-brand-lightblue dark:hover:bg-blue-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-blue transition-colors duration-200"
              >
                  상세 분석 보고서 보기
              </button>
          </div>
           <div className="text-sm text-gray-600 dark:text-gray-400 mt-4 pt-3 border-t border-blue-200 dark:border-blue-800">
              <p><strong>총 분석된 측정소:</strong> {totalStationsParsed}개</p>
              <p><strong>분석 완료된 산업단지:</strong> {totalComplexesAnalyzed}개</p>
          </div>
        </div>

        <div className="mb-8">
            <button 
                onClick={() => setIsCriteriaVisible(!isCriteriaVisible)}
                className="w-full flex justify-between items-center text-left p-2 rounded-md hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
            >
                <span className="text-lg font-semibold text-brand-darkgray dark:text-gray-200">평가 기준 안내</span>
                <ChevronDownIcon className={`h-5 w-5 text-gray-500 dark:text-gray-400 transition-transform duration-200 ${isCriteriaVisible ? 'rotate-180' : ''}`} />
            </button>
            {isCriteriaVisible && (
                <div className="mt-4 animate-fade-in-fast">
                    <ScoringCriteriaTable mode={pollutantType} />
                </div>
            )}
        </div>

        {rankedComplexes.length > 0 ? (
          <section>
            <h3 className="text-xl font-semibold text-brand-darkgray dark:text-gray-100 mb-4">{pdfReportTemplate.portfolio_section_title}</h3>
            <p className="text-sm text-gray-500 dark:text-gray-400 mb-2 text-right">* 항목을 클릭하면 지도와 상세 정보를 확인할 수 있습니다.</p>
             <div className="overflow-x-auto rounded-lg border dark:border-gray-700">
                <table className="w-full text-left">
                    <thead className="bg-brand-gray dark:bg-gray-700">
                        <tr className="border-b dark:border-gray-600">
                            <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200">순위</th>
                            <th className="p-3 font-semibold text-sm text-gray-700 dark:text-gray-200">산업단지</th>
                            <th className="p-3 font-semibold text-sm text-gray-700 dark:text-gray-200">근거 측정소<span className="block font-normal text-xs">(거리)</span></th>
                            <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200">최근농도<span className="block font-normal text-xs">({pollutantType === 'PM2.5' ? 'µg/m³' : 'ppm'})</span></th>
                            <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200">최고농도<span className="block font-normal text-xs">({pollutantType === 'PM2.5' ? 'µg/m³' : 'ppm'})</span></th>
                            <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200">총점</th>

                            {pollutantType === 'PM2.5' ? (
                                <>
                                    <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200" title="U1+U2">시급성(U)</th>
                                    <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200" title="S1+S2">심각성(S)</th>
                                    <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200" title="P1">지속성(P)</th>
                                    <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200" title="D1+D2">신뢰성(D)</th>
                                </>
                            ) : (
                                <>
                                    <th className="p-3 text-center font-semibold text-sm text-gray-700 dark:text-gray-200">시급성(U)</th>
