import React from 'react';
import appConfig from '../config/app_config';
import { ScoringCriteria, OzoneCriteria, PollutantType } from '../types';

interface ScoringCriteriaTableProps {
    title?: string;
    mode?: PollutantType;
}

export const ScoringCriteriaTable: React.FC<ScoringCriteriaTableProps> = ({ title, mode = 'PM2.5' }) => {
    const critPM: ScoringCriteria = appConfig.scoringCriteria;
    const critO3: OzoneCriteria = appConfig.ozoneCriteria;

    const pmData = [
        { category: '시급성 (U)', component: 'U1 (최신농도)', description: `최신 1시간 평균 농도 1µg/m³당 0.5점 부여. (${critPM.U1.threshold_high}µg/m³ 이상에서 최고점)`, maxScore: critPM.U1.max_score },
        { category: '시급성 (U)', component: 'U2 (급상승)', description: `최근 2시간 농도 변화량 기반. 농도 상승폭이 ${critPM.U2.threshold_high}µg/m³일 때 최고점.`, maxScore: critPM.U2.max_score },
        { category: '심각성 (S)', component: 'S1 (최대농도)', description: `분석 기간 내 5분 단위 최대 농도 1µg/m³당 0.2점 부여. (${critPM.S1.threshold_high}µg/m³ 이상에서 최고점)`, maxScore: critPM.S1.max_score },
        { category: '심각성 (S)', component: 'S2 (최근성)', description: '최대 농도 발생 시점이 최근일수록 높은 점수.', maxScore: critPM.S2.max_score },
        { category: '지속성 (P)', component: 'P1 (평균농도)', description: `평균 농도 ${critPM.P1.threshold_low}µg/m³ 이상일 때 초과분 1µg/m³당 0.5점 부여. (${critPM.P1.threshold_high}µg/m³ 이상에서 최고점)`, maxScore: critPM.P1.max_score },
        { category: '신뢰성 (D)', component: 'D1 (데이터품질)', description: `이상 최고농도(${critPM.D1.anomaly_threshold}µg/m³) 감지 시 ${critPM.D1.penalty_anomaly}점, 장기 동일값(${critPM.D1.constant_run_threshold / 12}시간) 감지 시 ${critPM.D1.penalty_constant}점 감점.`, maxScore: 0 },
        { category: '신뢰성 (D)', component: 'D2 (근접성 점수)', description: `산업단지와 측정소 거리가 가까울수록 높은 점수 부여. ${critPM.D2.max_distance_km}km 이상 시 0점, 0km 근접 시 최고점.`, maxScore: critPM.D2.max_score },
    ];

    const ozoneData = [
        { category: '시급성 (U)', component: 'Urgency', description: critO3.U.description, maxScore: '가변' },
        { category: '심각성 (S)', component: 'Severity', description: `(기간 내 최대 농도 / ${critO3.S.standard_val}) × ${critO3.S.multiplier}`, maxScore: '가변' },
        { category: '지속성 (P)', component: 'Persistence', description: `(${critO3.P.threshold}ppm 초과 데이터 수 / 전체 데이터) × ${critO3.P.multiplier}`, maxScore: critO3.P.multiplier },
        { category: '신뢰성 (D)', component: 'Reliability', description: `기본 ${critO3.D.base_score}점 - (거리(km) × ${critO3.D.penalty_per_km}). ${critO3.D.max_dist}km 이상 시 0점.`, maxScore: critO3.D.base_score },
    ];

    const criteriaData = mode === 'PM2.5' ? pmData : ozoneData;

    const mergedRows = [];
    let lastCategory = '';

    criteriaData.forEach((item, index) => {
        if (item.category !== lastCategory) {
            const rowSpan = criteriaData.filter(d => d.category === item.category).length;
            mergedRows.push({ ...item, rowSpan, isFirst: true });
            lastCategory = item.category;
        } else {
            mergedRows.push({ ...item, rowSpan: 1, isFirst: false });
        }
    });

    return (
        <section>
            {title && <h3 className="text-xl font-semibold text-brand-darkgray dark:text-gray-200 mb-4">{title}</h3>}
            <div className="overflow-x-auto rounded-lg border dark:border-gray-700">
                <table className="w-full text-left text-sm">
                    <thead className="bg-brand-gray dark:bg-gray-700 text-gray-700 dark:text-gray-200">
                        <tr>
                            <th className="p-3 font-semibold w-1/6">구분</th>
                            <th className="p-3 font-semibold w-1/6">항목</th>
                            <th className="p-3 font-semibold w-2/3">산정 기준</th>
                            <th className="p-3 text-center font-semibold">최고점/배점</th>
                        </tr>
                    </thead>
                    <tbody>
                        {mergedRows.map((item, index) => (
                            <tr key={index} className="border-b dark:border-gray-600 last:border-b-0 hover:bg-gray-50 dark:hover:bg-gray-700">
                                {item.isFirst && <td className="p-3 align-top text-gray-800 dark:text-gray-300" rowSpan={item.rowSpan}>{item.category}</td>}
                                <td className="p-3 font-medium text-gray-800 dark:text-gray-300">{item.component}</td>
                                <td className="p-3 text-gray-600 dark:text-gray-400">{item.description}</td>
                                <td className="p-3 text-center font-medium text-gray-800 dark:text-gray-300">{typeof item.maxScore === 'number' && item.maxScore <= 0 ? '감점' : item.maxScore}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </section>
    );
};

export type PollutantType = 'PM2.5' | 'O3';

export interface ParsingRules {
  description: string;
  station_name_row_index: number;
  summary_rows_map: { [key: string]: string };
  data_start_identifier: string;
  value_column_step: number;
  station_name_clean_pattern: string;
}

export interface IndustrialComplex {
  name: string;
  address: string;
  lat: number;
  lon: number;
}

export interface StationCoordinates {
  [stationName: string]: {
    lat: number;
    lon: number;
    address: string;
  };
}

export interface ScoringCriteria {
    U1: { threshold_low: number; threshold_high: number; max_score: number; };
    U2: { threshold_high: number; max_score: number; };
    S1: { threshold_low: number; threshold_high: number; max_score: number; };
    S2: { max_score: number; };
    P1: { threshold_low: number; threshold_high: number; max_score: number; };
    D1: { 
      anomaly_threshold: number; penalty_anomaly: number;
      constant_run_threshold: number; penalty_constant: number;
    };
    D2: {
        max_score: number;
        max_distance_km: number;
    };
}

export interface OzoneCriteria {
    U: { description: string; multiplier: number; max_score: number };
    S: { standard_val: number; multiplier: number; max_score: number };
    P: { threshold: number; multiplier: number; max_score: number };
    D: { base_score: number; penalty_per_km: number; max_dist: number };
}

export interface PdfReportTemplate {
  title: string;
  author: string;
  summary_template: string;
  portfolio_section_title: string;
  integrity_section_title: string;
  item_template: string;
}

export interface AppConfig {
  appName: string;
  version: string;
  parsingRules: ParsingRules;
  industrialComplexes: IndustrialComplex[];
  stationCoordinates: StationCoordinates;
  scoringCriteria: ScoringCriteria;
  ozoneCriteria: OzoneCriteria;
  pdfReportTemplate: PdfReportTemplate;
}

export interface TimeSeriesData {
  timestamp: string;
  value: number | null;
}

export interface StationScores {
  // PM2.5 specific
  u1?: number;
  u2?: number;
  s1?: number;
  s2?: number;
  p1?: number;
  d1?: number;
  d2?: number;

  // Ozone specific
  u?: number;
  s?: number;
  p?: number;
  d?: number;

  total: number;
  components: { [key: string]: number | string | null };
}

export interface StationMetrics {
  [key: string]: any;
  full_period_avg?: number;
  full_period_max?: number;
  full_period_min?: number;
  latest_1hr_avg?: number;
  c_2h_ago?: number | null;
  delta_2hr?: number | null;
  max_value_timestamp?: string | null;
  longest_constant_run: number;

  // Ozone Specific
  ozone_exceed_count?: number; // Count > 0.06
  total_valid_count?: number;
  latest_value?: number;
  prev_1hr_value?: number;
}

export interface StationData {
  id: number;
  name: string;
  fullName: string;
  metrics: StationMetrics;
  timeseries: TimeSeriesData[];
  scores: StationScores | null;
}

export interface AnalyzedComplex {
  complex: IndustrialComplex;
  station: StationData;
  distanceKm: number;
  stationLat?: number;
  stationLon?: number;
  stationAddress?: string;
}

export interface AnalysisResult {
  pollutantType: PollutantType;
  rankedComplexes: AnalyzedComplex[];
  startTimestamp: string;
  endTimestamp: string;
  totalStationsParsed: number;
  totalComplexesAnalyzed: number;
  unmatchedComplexes: string[];
}

import { StationData, AnalysisResult, StationScores, TimeSeriesData, IndustrialComplex, AnalyzedComplex, PollutantType, AppConfig } from '../types';
import config from '../config/app_config';

const { parsingRules, scoringCriteria, ozoneCriteria, industrialComplexes, stationCoordinates } = config;

/**
 * Finds coordinates for a station by trying exact, normalized (space-insensitive), and substring matches.
 */
function findStationCoords(stationName: string, coordsConfig: { [key: string]: { lat: number; lon: number; address?: string } }) {
    if (coordsConfig[stationName]) return coordsConfig[stationName];

    const normalizedStationName = stationName.replace(/\s/g, '');
    const matchingKey = Object.keys(coordsConfig).find(key => 
        key.replace(/\s/g, '') === normalizedStationName
    );
    if (matchingKey) return coordsConfig[matchingKey];

    if (stationName.length > 1) { 
        const substringKey = Object.keys(coordsConfig).find(key => key.includes(stationName));
        if (substringKey) return coordsConfig[substringKey];
    }

    return null;
}

function parseCsvWithQuotes(csvContent: string): string[][] {
    const rows: string[][] = [];
    let currentRow: string[] = [];
    let currentField = '';
    let inQuotes = false;

    if (csvContent.charCodeAt(0) === 0xFEFF) {
        csvContent = csvContent.slice(1);
    }
    csvContent = csvContent.replace(/\r\n/g, '\n');

    for (let i = 0; i < csvContent.length; i++) {
        const char = csvContent[i];
        if (inQuotes) {
            if (char === '"') {
                if (i + 1 < csvContent.length && csvContent[i + 1] === '"') {
                    currentField += '"';
                    i++;
                } else {
                    inQuotes = false;
                }
            } else {
                currentField += char;
            }
        } else {
            if (char === '"') {
                inQuotes = true;
            } else if (char === ',') {
                currentRow.push(currentField);
                currentField = '';
            } else if (char === '\n') {
                currentRow.push(currentField);
                rows.push(currentRow);
                currentRow = [];
                currentField = '';
            } else {
                currentField += char;
            }
        }
    }
    currentRow.push(currentField);
    rows.push(currentRow);

    return rows.filter(row => row.length > 1 || (row.length === 1 && row[0].trim() !== ''));
}

function parseCsv(csvContent: string): StationData[] {
    const rows = parseCsvWithQuotes(csvContent);
    if (rows.length < parsingRules.station_name_row_index + 2) return [];

    const stationNamesRaw = rows[parsingRules.station_name_row_index];
    const stationData: StationData[] = [];

    for (let i = 1; i < stationNamesRaw.length; i += parsingRules.value_column_step) {
        const rawName = stationNamesRaw[i];
        if (rawName && rawName.trim()) {
            const cleanName = rawName
                .replace(/\n/g, ' ')
                .replace(/\([^)]+\)/g, '')
                .trim()
                .replace(/\s+/g, ' ');

            if (cleanName) {
                stationData.push({
                    id: stationData.length,
                    name: cleanName,
                    fullName: rawName.trim().replace(/\n/g, ' '),
                    metrics: { longest_constant_run: 0 },
                    timeseries: [],
                    scores: null,
                });
            }
        }
    }

    if (stationData.length === 0) return [];

    rows.forEach(columns => {
        const rowHeader = columns[0].trim();
        if (rowHeader.startsWith(parsingRules.data_start_identifier)) {
            const timestamp = rowHeader;
            for (let i = 0; i < stationData.length; i++) {
                const valueIndex = 1 + (i * parsingRules.value_column_step);
                if (columns.length > valueIndex) {
                    const valueStr = columns[valueIndex]?.trim();
                    const parsedVal = valueStr ? parseFloat(valueStr) : NaN;
                    // Initial Parsing: Just parse, filter specifics later based on PollutantType
                    const value = !isNaN(parsedVal) ? parsedVal : null;

                    if(stationData[i]) {
                        stationData[i].timeseries.push({ timestamp, value });
                    }
                }
            }
        } else if (parsingRules.summary_rows_map[rowHeader]) {
             // Summary rows are mostly relevant for PM2.5 basic view, 
             // for Ozone we recalculate metrics from timeseries mostly.
            const metricKey = parsingRules.summary_rows_map[rowHeader];
            for (let i = 0; i < stationData.length; i++) {
                const valueIndex = 1 + (i * parsingRules.value_column_step);
                if (columns.length > valueIndex) {
                    const valueStr = columns[valueIndex]?.trim();
                    const parsedVal = valueStr ? parseFloat(valueStr) : NaN;
                    const value = (!isNaN(parsedVal) && parsedVal > 0) ? parsedVal : 0;

                     if(stationData[i]) {
                        stationData[i].metrics[metricKey] = value;
                    }
                }
            }
        }
    });

    return stationData;
}

// Applies Ozone specific preprocessing: Outlier removal (> 1.0) and Forward Fill
function preprocessOzoneData(station: StationData) {
    // 1. Remove Outliers (> 1.0 ppm)
    station.timeseries.forEach(pt => {
        if (pt.value !== null && pt.value >= 1.0) {
            pt.value = null; 
        }
    });

    // 2. Forward Fill (ffill)
    // Iterate and fill nulls with previous valid value
    let lastValidValue: number | null = null;
    station.timeseries.forEach(pt => {
        if (pt.value !== null) {
            lastValidValue = pt.value;
        } else if (lastValidValue !== null) {
            pt.value = lastValidValue;
        }
    });
}

function calculateAdditionalMetricsPM25(station: StationData): void {
    // Simple filter for PM2.5: Remove <= 0 values for calculation
    const validTimeseries = station.timeseries.filter(ts => ts.value !== null && ts.value > 0) as {timestamp: string, value: number}[];

    if (validTimeseries.length === 0) {
        station.metrics.longest_constant_run = 0;
        return;
    };

    if (validTimeseries.length >= 12) {
        const last12 = validTimeseries.slice(-12);
        const sum = last12.reduce((acc, curr) => acc + curr.value, 0);
        station.metrics.latest_1hr_avg = parseFloat((sum / last12.length).toFixed(2));
    }

    if (validTimeseries.length >= 24) {
        const value2hAgo = validTimeseries[validTimeseries.length - 24].value;
        station.metrics.c_2h_ago = value2hAgo;
        if (station.metrics.latest_1hr_avg !== undefined && value2hAgo !== null) {
            station.metrics.delta_2hr = station.metrics.latest_1hr_avg - value2hAgo;
        }
    }

    if (station.metrics.full_period_max) {
        const maxTs = [...validTimeseries].reverse().find(ts => ts.value === station.metrics.full_period_max);
        station.metrics.max_value_timestamp = maxTs ? maxTs.timestamp : null;
    }

    let longestRun = 0;
    let currentRun = 0;
    let lastValue: number | null = -Infinity;
    for (const ts of validTimeseries) {
        if (ts.value !== null && ts.value === lastValue) {
            currentRun++;
        } else {
            longestRun = Math.max(longestRun, currentRun);
            currentRun = 1;
            lastValue = ts.value;
        }
    }
    station.metrics.longest_constant_run = Math.max(longestRun, currentRun);
}

function formatTimestamp(timestamp: string): string {
    try {
        const standardized = timestamp.replace(/\./g, '-'); 
        const date = new Date(standardized);
        if (isNaN(date.getTime())) return timestamp;
        return `${date.getMonth() + 1}월 ${date.getDate()}일 ${date.getHours()}시 ${date.getMinutes()}분`;
    } catch (e) {
        return timestamp;
    }
}

function calculatePM25Scores(station: StationData): StationScores {
    const { metrics, timeseries } = station;
    const crit = scoringCriteria;
    const components: { [key: string]: number | string | null } = {};

    const cNow = metrics.latest_1hr_avg;
    let u1 = 0;
    if (cNow !== undefined) {
        const val = cNow * 0.5;
        u1 = Math.min(crit.U1.max_score, Math.max(0, val));
    }
    components['최신 1시간 농도'] = cNow !== undefined ? `${cNow}µg/m³` : 'N/A';

    const deltaC = metrics.delta_2hr;
    let u2 = 0;
    if (deltaC !== undefined && deltaC !== null) {
        const val = crit.U2.max_score * deltaC / crit.U2.threshold_high;
        u2 = Math.min(crit.U2.max_score, Math.max(0, val));
    }
    components['2시간 농도 변화'] = deltaC !== undefined && deltaC !== null ? `${deltaC.toFixed(1)}µg/m³` : 'N/A';

    const cMax = metrics.full_period_max;
    let s1 = 0;
    if (cMax !== undefined) {
        const val = cMax * 0.2;
        s1 = Math.min(crit.S1.max_score, Math.max(0, val));
    }
    components['기간 최대 농도'] = cMax !== undefined ? `${cMax}µg/m³` : 'N/A';

    let s2 = 0;
    if (metrics.max_value_timestamp && timeseries.length > 1) {
        const tFirst = new Date(timeseries[0].timestamp).getTime();
        const tLast = new Date(timeseries[timeseries.length - 1].timestamp).getTime();
        const tMax = new Date(metrics.max_value_timestamp).getTime();
        if (tLast > tFirst) {
            const ratio = (tMax - tFirst) / (tLast - tFirst);
            s2 = crit.S2.max_score * Math.min(1, Math.max(0, ratio));
        }
    }
    components['최대농도 최근성'] = metrics.max_value_timestamp ? formatTimestamp(metrics.max_value_timestamp) : 'N/A';

    const cMean = metrics.full_period_avg;
    let p1 = 0;
    if (cMean !== undefined && cMean >= crit.P1.threshold_low) {
        const val = (cMean - crit.P1.threshold_low) * 0.5;
        p1 = Math.min(crit.P1.max_score, Math.max(0, val));
    }
    components['기간 평균 농도'] = cMean !== undefined ? `${cMean}µg/m³` : 'N/A';

    let d1 = 0;
    if (metrics.full_period_max && metrics.full_period_max >= crit.D1.anomaly_threshold) {
        d1 = crit.D1.penalty_anomaly;
    } else if (metrics.longest_constant_run >= crit.D1.constant_run_threshold) {
        d1 = crit.D1.penalty_constant;
    }
    components['이상값'] = metrics.full_period_max && metrics.full_period_max >= crit.D1.anomaly_threshold ? metrics.full_period_max : '없음';
    components['장기 동일값'] = metrics.longest_constant_run >= crit.D1.constant_run_threshold ? `${metrics.longest_constant_run}회` : '없음';

    const total = u1 + u2 + s1 + s2 + p1 + d1;

    return {
        u1: parseFloat(u1.toFixed(1)), u2: parseFloat(u2.toFixed(1)), s1: parseFloat(s1.toFixed(1)),
        s2: parseFloat(s2.toFixed(1)), p1: parseFloat(p1.toFixed(1)), d1: parseFloat(d1.toFixed(1)),
        d2: 0,
        total: parseFloat(Math.max(0, total).toFixed(1)), components,
    };
}

function calculateOzoneScores(station: StationData): StationScores {
    const { timeseries } = station;
    const validData = timeseries.filter(d => d.value !== null);
    const count = validData.length;

    if (count === 0) {
        return { total: 0, components: {}, u:0, s:0, p:0, d:0 };
    }

    // Sort by time to ensure order
    validData.sort((a, b) => a.timestamp.localeCompare(b.timestamp));

    const current = validData[validData.length - 1];

    const currTime = new Date(current.timestamp).getTime();
    let prev1HrVal = current.value; // Default to current if not found

    // Look back for a point close to 60 mins ago (tolerance +/- 10 mins)
    for (let i = validData.length - 2; i >= 0; i--) {
        const t = new Date(validData[i].timestamp).getTime();
        const diffMins = (currTime - t) / (1000 * 60);
        if (diffMins >= 50 && diffMins <= 70) {
            prev1HrVal = validData[i].value;
            break;
        }
        if (diffMins > 70) break; // Gone too far
    }

    // 1. (U) Urgency
    // (Current - 1hr_ago) * Multiplier. If negative, 0. Clamped to Max Score.
    const uRaw = ((current.value || 0) - (prev1HrVal || 0)) * ozoneCriteria.U.multiplier;
    const uScore = Math.min(ozoneCriteria.U.max_score, Math.max(0, uRaw));

    // 2. (S) Severity
    // (Max / Standard) * Multiplier. Clamped to Max Score.
    const maxVal = Math.max(...validData.map(d => d.value || 0));
    const sRaw = (maxVal / ozoneCriteria.S.standard_val) * ozoneCriteria.S.multiplier;
    const sScore = Math.min(ozoneCriteria.S.max_score, sRaw);

    // 3. (P) Persistence
    // (Count > Threshold / Total) * Multiplier. Clamped to Max Score.
    const exceedCount = validData.filter(d => (d.value || 0) > ozoneCriteria.P.threshold).length;
    const pRaw = (exceedCount / count) * ozoneCriteria.P.multiplier;
    const pScore = Math.min(ozoneCriteria.P.max_score, pRaw);

    // 4. (D) Reliability -> Calculated in analyzeData using distance. 
    const dScore = 0; // Placeholder

    // Save metrics for display
    station.metrics.full_period_max = maxVal;
    station.metrics.latest_1hr_avg = current.value || 0; // reusing this field for "Current"
    station.metrics.ozone_exceed_count = exceedCount;
    station.metrics.total_valid_count = count;
    station.metrics.prev_1hr_value = prev1HrVal || 0;

    const components = {
        'U_val': `${uScore.toFixed(1)}점 (현재: ${current.value}, 1시간전: ${prev1HrVal})`,
        'S_val': `${sScore.toFixed(1)}점 (최대: ${maxVal})`,
        'P_val': `${pScore.toFixed(1)}점 (초과빈도: ${(exceedCount/count*100).toFixed(1)}%)`,
        '최신 농도': `${current.value}ppm`,
        '최대 농도': `${maxVal}ppm`,
    };

    return {
        u: parseFloat(uScore.toFixed(1)),
        s: parseFloat(sScore.toFixed(1)),
        p: parseFloat(pScore.toFixed(1)),
        d: 0, // Placeholder
        d1: 0, d2: 0, // PM2.5 fields (unused)
        total: parseFloat((uScore + sScore + pScore).toFixed(1)),
        components
    };
}

function haversineDistance(lat1: number, lon1: number, lat2: number, lon2: number): number {
    const R = 6371; // Radius of Earth in kilometers
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
              Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
              Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c;
}

export function analyzeData(csvContents: string[], selectedComplexNames: string[], pollutantType: PollutantType = 'PM2.5'): AnalysisResult {
    const allStationsRaw = csvContents.flatMap(content => parseCsv(content));

    if (allStationsRaw.length === 0) {
        throw new Error("제공된 파일에서 유효한 측정소 데이터를 찾을 수 없습니다. 파일 형식과 내용을 확인해주세요.");
    }

    // Deduplicate stations
    const stationMap = new Map<string, StationData>();
    allStationsRaw.forEach(station => stationMap.set(station.name, station));
    const uniqueStations = Array.from(stationMap.values());
    uniqueStations.forEach((station, index) => station.id = index);

    // Filter complexes
    const selectedComplexes = industrialComplexes.filter(c => selectedComplexNames.includes(c.name));
    const analyzedComplexes: AnalyzedComplex[] = [];

    selectedComplexes.forEach(complex => {
        let closestStation: StationData | null = null;
        let minDistance = Infinity;
        let closestStationCoord: { lat: number, lon: number, address?: string } | null = null;

        uniqueStations.forEach(station => {
            const stationCoord = findStationCoords(station.name, stationCoordinates);
            if (stationCoord) {
                const distance = haversineDistance(complex.lat, complex.lon, stationCoord.lat, stationCoord.lon);
                if (distance < minDistance) {
                    minDistance = distance;
                    closestStation = station;
                    closestStationCoord = stationCoord;
                }
            }
        });

        if (closestStation) {
            // Apply preprocessing and Scoring ONLY IF not already calculated or type changed (implied new run)
            if (!closestStation.scores) { 
                if (pollutantType === 'O3') {
                    preprocessOzoneData(closestStation);
                    closestStation.scores = calculateOzoneScores(closestStation);
                } else {
                    calculateAdditionalMetricsPM25(closestStation);
                    closestStation.scores = calculatePM25Scores(closestStation);
                }
            }

            if (closestStation.scores) {
                const stationCopy: StationData = JSON.parse(JSON.stringify(closestStation));

                if (pollutantType === 'PM2.5') {
                    // PM2.5 Distance Logic (D2)
                    const { max_score, max_distance_km } = scoringCriteria.D2;
                    const proximityScore = Math.max(0, max_score * (1 - minDistance / max_distance_km));
                    stationCopy.scores!.d2 = parseFloat(proximityScore.toFixed(1));

                    const { u1=0, u2=0, s1=0, s2=0, p1=0, d1=0, d2=0 } = stationCopy.scores!;
                    const newTotal = u1 + u2 + s1 + s2 + p1 + d1 + d2;
                    stationCopy.scores!.total = parseFloat(Math.max(0, newTotal).toFixed(1));
                    stationCopy.scores!.components['근접성 점수'] = `${stationCopy.scores!.d2}점 (${minDistance.toFixed(1)}km)`;
                } else {
                    // Ozone Distance Logic (D)
                    // base - (distance * penalty). Clamped 0.
                    let dScore = ozoneCriteria.D.base_score - (minDistance * ozoneCriteria.D.penalty_per_km);
                    dScore = Math.max(0, dScore);

                    stationCopy.scores!.d = parseFloat(dScore.toFixed(1));

                    // Ozone Total = U + S + P + D
                    const { u=0, s=0, p=0 } = stationCopy.scores!;
                    const newTotal = u + s + p + dScore;
                    stationCopy.scores!.total = parseFloat(newTotal.toFixed(1));
                    stationCopy.scores!.components['D_val'] = `${dScore.toFixed(1)}점 (${minDistance.toFixed(1)}km)`;
                }

                 analyzedComplexes.push({
                    complex: complex,
                    station: stationCopy,
                    distanceKm: minDistance,
                    stationLat: closestStationCoord?.lat,
                    stationLon: closestStationCoord?.lon,
                    stationAddress: closestStationCoord?.address
                });
            }
        }
    });

    if (analyzedComplexes.length === 0) {
        throw new Error(`선택한 산업단지와 매칭되는 유효한 측정소 데이터를 찾을 수 없습니다.`);
    }

    const rankedComplexes = analyzedComplexes
        .sort((a, b) => b.station.scores!.total - a.station.scores!.total);

    let startTimestamp = "N/A";
    let endTimestamp = "N/A";
    const allValidTimestamps = uniqueStations
      .flatMap(s => s.timeseries)
      .map(ts => ts.timestamp)
      .filter((ts): ts is string => !!ts);

    if (allValidTimestamps.length > 0) {
        allValidTimestamps.sort((a, b) => a.localeCompare(b));
        startTimestamp = allValidTimestamps[0];
        endTimestamp = allValidTimestamps[allValidTimestamps.length - 1];
    }

    return {
        pollutantType,
        rankedComplexes,
        startTimestamp,
        endTimestamp,
        totalStationsParsed: uniqueStations.length,
        totalComplexesAnalyzed: rankedComplexes.length,
        unmatchedComplexes: [], 
    };
}

import React from 'react';
import appConfig from '../config/app_config';
import { ScoringCriteria, OzoneCriteria, PollutantType } from '../types';

interface ScoringCriteriaTableProps {
    title?: string;
    mode?: PollutantType;
}

